  /**
   * Parse teams from game string
   * @param {string} gameString - Game string like "Team A @ Team B"
   * @returns {Object} { away, home }
   */
  function parseTeamsFromGame(gameString) {
    if (!gameString) return { away: "", home: "" };

    const separators = ["@", " vs ", " vs. ", " / "];
    for (const sep of separators) {
      if (gameString.includes(sep)) {
        const parts = gameString.split(sep);
        return {
          away: parts[0].trim(),
          home: parts[1] ? parts[1].trim() : "",
        };
      }
    }

    return { away: gameString.trim(), home: "" };
  }

  /**
   * Escape HTML to prevent XSS
   * @param {string} text - Text to escape
   * @returns {string} Escaped HTML
   */
  function escapeHtml(text) {
    const div = document.createElement("div");
    div.textContent = text;
    return div.innerHTML;
  }

  /**
   * Format file size for display
   * @param {number} bytes - File size in bytes
   * @returns {string} Formatted file size
   */
  function formatFileSize(bytes) {
    if (bytes < 1024) return bytes + " B";
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + " KB";
    return (bytes / (1024 * 1024)).toFixed(1) + " MB";
  }

  /**
   * Debounce function - delays execution until after wait ms have elapsed
   * since the last time the debounced function was invoked
   * @param {Function} func - Function to debounce
   * @param {number} wait - Milliseconds to wait (default: 150)
   * @param {boolean} immediate - Execute on leading edge instead of trailing
   * @returns {Function} Debounced function with cancel() method
   */
  function debounce(func, wait = 150, immediate = false) {
    let timeout;

    function debounced(...args) {
      const context = this;
      const later = function () {
        timeout = null;
        if (!immediate) func.apply(context, args);
      };
      const callNow = immediate && !timeout;
      clearTimeout(timeout);
      timeout = setTimeout(later, wait);
      if (callNow) func.apply(context, args);
    }

    debounced.cancel = function () {
      clearTimeout(timeout);
      timeout = null;
    };

    return debounced;
  }

  /**
   * Throttle function - ensures function is called at most once per wait period
   * @param {Function} func - Function to throttle
   * @param {number} wait - Minimum ms between calls (default: 100)
   * @returns {Function} Throttled function
   */
  function throttle(func, wait = 100) {
    let lastCall = 0;
    let timeout = null;

    return function throttled(...args) {
      const context = this;
      const now = Date.now();
      const remaining = wait - (now - lastCall);

      if (remaining <= 0 || remaining > wait) {
        if (timeout) {
          clearTimeout(timeout);
          timeout = null;
        }
        lastCall = now;
        func.apply(context, args);
      } else if (!timeout) {
        timeout = setTimeout(function () {
          lastCall = Date.now();
          timeout = null;
          func.apply(context, args);
        }, remaining);
      }
    };
  }

  /**
   * Format date for display
   * @param {string|Date} date - Date to format
   * @returns {string} Formatted date (MM/DD/YYYY)
   */
  function formatDate(date) {
    if (!date) return "TBD";
    const d = new Date(date);
    if (isNaN(d.getTime())) return "TBD";
    const month = (d.getMonth() + 1).toString().padStart(2, "0");
    const day = d.getDate().toString().padStart(2, "0");
    const year = d.getFullYear();
    return `${month}/${day}/${year}`;
  }

  /**
   * Format time for display
   * @param {string|Date} date - Date/time to format
   * @returns {string} Formatted time (HH:MM AM/PM)
   */
  function formatTime(date) {
    if (!date) return "TBD";
    const d = new Date(date);
    if (isNaN(d.getTime())) return "TBD";
    return d.toLocaleTimeString("en-US", {
      hour: "2-digit",
      minute: "2-digit",
      hour12: true,
    });
  }

