/**
 * Model Endpoint Resolver v34.00.0
 *
 * PURPOSE:
 * - Centralizes how front-end fetchers resolve model endpoints (API + Function)
 * - Reads dynamic registry values hydrated by model-endpoints-bootstrap.js
 * - Falls back to sane defaults so missing config never breaks fetching
 *
 * RELATIONSHIP WITH model-endpoints-bootstrap.js:
 * - Bootstrap runs FIRST at page load to fetch /api/registry
 * - Bootstrap updates APP_CONFIG with fresh Container App URLs
 * - Resolver provides HELPER FUNCTIONS for fetchers to access those URLs
 * - Resolver has DEFAULT fallbacks if bootstrap fails or times out
 *
 * USAGE:
 *   window.ModelEndpointResolver.getApiEndpoint('nba')
 *   // Returns: APP_CONFIG.NBA_API_URL || DEFAULTS.nba.api
 */
(function() {
    'use strict';

    const DEFAULTS = {};

    const normKey = (league) => String(league || '').toLowerCase();

    const getApiEndpoint = (league) => {
        const key = normKey(league);
        const configKey = `${key.toUpperCase()}_API_URL`;
        const fromConfig = window.APP_CONFIG?.[configKey];
        if (fromConfig && typeof fromConfig === 'string') return fromConfig;
        const base = window.APP_CONFIG?.API_BASE_FALLBACK || window.APP_CONFIG?.API_BASE_URL || `${window.location.origin}/api`;
        if (base) return `${base}/${key}`;
        return DEFAULTS[key]?.api || '';
    };

    const getFunctionEndpoint = (league) => {
        const key = normKey(league);
        const configKey = `${key.toUpperCase()}_FUNCTION_URL`;
        const fromConfig = window.APP_CONFIG?.[configKey];
        if (fromConfig && typeof fromConfig === 'string') return fromConfig;
        return DEFAULTS[key]?.func || '';
    };

    const ensureRegistryHydrated = async () => {
        if (window.ModelEndpointBootstrap?.hydrate) {
            try {
                await window.ModelEndpointBootstrap.hydrate();
            } catch (err) {
                // Safe to ignore; defaults will be used.
                console.warn('[MODEL-ENDPOINT-RESOLVER] Registry hydrate failed:', err.message);
            }
        }
    };

    window.ModelEndpointResolver = {
        getApiEndpoint,
        getFunctionEndpoint,
        ensureRegistryHydrated
    };
})();


/* === assets/js/features/model-endpoints-bootstrap.js === */
/**
 * Model Endpoints Bootstrap v34.00.0
 * 
 * PURPOSE:
 * Fetch model endpoints from the orchestrator registry so front-end stays in sync
 * with updated Azure Container App URLs without redeploying static assets.
 *
 * EXECUTION ORDER:
 * 1. Runs IMMEDIATELY at page load (not deferred)
 * 2. Fetches /api/registry with 6-second timeout
 * 3. Updates APP_CONFIG.{NBA|NCAAM|NFL|NCAAF}_API_URL dynamically
 * 4. Falls back to config.js defaults if registry unavailable
 * 
 * RELATIONSHIP WITH model-endpoint-resolver.js:
 * - Bootstrap UPDATES APP_CONFIG at page load
 * - Resolver READS FROM APP_CONFIG when fetchers need endpoints
 * - Together they enable zero-downtime Container App updates
 *
 * Supports dynamic discovery of new leagues - any key in the registry with an
 * 'endpoint' property will be added to APP_CONFIG as {KEY}_API_URL.
 */
(function() {
    'use strict';

    const REGISTRY_TIMEOUT_MS = 6000;

    // Known leagues to look for (can be extended by registry response)
    const KNOWN_LEAGUES = ['nba', 'ncaam', 'nfl', 'ncaaf', 'nhl', 'mlb'];

    const fetchWithTimeout = async (url, timeoutMs = REGISTRY_TIMEOUT_MS) => {
        const controller = new AbortController();
        const timer = setTimeout(() => controller.abort(), timeoutMs);
        try {
            const response = await fetch(url, { signal: controller.signal, headers: { 'Accept': 'application/json' } });
            clearTimeout(timer);
            return response;
        } catch (err) {
            clearTimeout(timer);
            throw err;
        }
    };

    const hydrateEndpoints = async () => {
        // Check if dynamic registry is enabled - if not, skip network calls entirely
        if (!window.APP_CONFIG?.DYNAMIC_REGISTRY_ENABLED) {
            console.log('[MODEL-ENDPOINTS] Dynamic registry disabled - using static config.js endpoints');
            console.log('[MODEL-ENDPOINTS] • To enable dynamic registry, set DYNAMIC_REGISTRY_ENABLED: true in config.js');
            console.log('[MODEL-ENDPOINTS] • Requires Azure Functions deployment with ModelRegistry function');
            window.APP_CONFIG.MODEL_ENDPOINTS_SOURCE = 'static';
            window.APP_CONFIG.MODEL_ENDPOINTS_LAST_UPDATED = new Date().toISOString();
            return;
        }

        const primaryBase = window.APP_CONFIG?.API_BASE_URL;
        const fallbackBase = window.APP_CONFIG?.API_BASE_FALLBACK;
        const functionsBase = window.APP_CONFIG?.FUNCTIONS_BASE_URL;

        const resolveRegistry = async (base) => {
            if (!base) return null;
            const url = `${base}/registry`;
            console.log('[MODEL-ENDPOINTS] Fetching model endpoints from registry:', url);
            const res = await fetchWithTimeout(url);
            if (!res.ok) throw new Error(`Registry request failed: ${res.status}`);
            const ct = (res.headers.get('content-type') || '').toLowerCase();
            if (!ct.includes('application/json')) {
                // Likely a SPA HTML fallback; treat as failure so we try the fallback base
                throw new Error(`Unexpected content-type: ${ct}`);
            }
            return await res.json();
        };

        let registry = null;
        const sources = [
            { name: 'primary', base: primaryBase },
            { name: 'fallback', base: fallbackBase },
            { name: 'functions', base: functionsBase ? `${functionsBase}/api` : null }
        ].filter(s => s.base);

        for (const source of sources) {
            try {
                registry = await resolveRegistry(source.base);
                if (registry) {
                    console.log(`[MODEL-ENDPOINTS] • Registry loaded from ${source.name}`);
                    break;
                }
            } catch (err) {
                console.warn(`[MODEL-ENDPOINTS] ${source.name} registry fetch failed:`, err.message);
            }
        }

        if (!registry) {
            console.warn('[MODEL-ENDPOINTS] Unable to refresh endpoints from registry (all sources failed)');
            console.log('[MODEL-ENDPOINTS] • Using fallback endpoints from config.js');
            console.log('[MODEL-ENDPOINTS] • Consider setting DYNAMIC_REGISTRY_ENABLED: false if registry not deployed');
            window.APP_CONFIG.MODEL_ENDPOINTS_SOURCE = 'static-fallback';
            return;
        }

        // Dynamically iterate over ALL keys in registry response
        // This allows new leagues/models to be added without code changes
        const registryKeys = Object.keys(registry || {});
        const allLeagues = [...new Set([...KNOWN_LEAGUES, ...registryKeys])];

        let updatedCount = 0;
        allLeagues.forEach((key) => {
            const entry = registry?.[key];
            if (entry?.endpoint) {
                const configKey = `${key.toUpperCase()}_API_URL`;
                const oldEndpoint = window.APP_CONFIG[configKey];
                window.APP_CONFIG[configKey] = entry.endpoint;
                updatedCount++;
                if (oldEndpoint !== entry.endpoint) {
                    console.log(`[MODEL-ENDPOINTS] Updated ${key.toUpperCase()} endpoint: ${entry.endpoint}`);
                }
            }
        });

        window.APP_CONFIG.MODEL_ENDPOINTS_LAST_UPDATED = new Date().toISOString();
        window.APP_CONFIG.MODEL_ENDPOINTS_COUNT = updatedCount;
        window.APP_CONFIG.MODEL_ENDPOINTS_SOURCE = 'registry';

        if (updatedCount > 0) {
            console.log(`[MODEL-ENDPOINTS] Hydrated ${updatedCount} endpoints from registry`);
        }
        console.log(`[MODEL-ENDPOINTS] • Registry hydration complete - ${updatedCount} endpoints updated`);
    };

    // Kick off hydration early so downstream fetchers use fresh endpoints
    hydrateEndpoints();

    // Expose for optional manual refresh/debug
    window.ModelEndpointBootstrap = {
        hydrate: hydrateEndpoints,
        getKnownLeagues: () => KNOWN_LEAGUES
    };
})();


/* === assets/js/features/base-sport-fetcher.js === */
/**
 * BaseSportFetcher v1.0
 * Shared fetch infrastructure for all sport model fetchers.
 * Eliminates duplicated fetchWithTimeout, cache, endpoint resolution,
 * health check, and fire-rating parsing across NBA/NCAAM/NFL/NCAAF/NHL.
 *
 * Each sport fetcher creates an instance with sport-specific config
 * and a formatPickForTable function.
 */

(function () {
  "use strict";

  const DEFAULT_CACHE_DURATION = 60000; // 1 minute
  const DEFAULT_TIMEOUT = 15000; // 15 seconds

  // ===== SHARED: fetchWithTimeout =====
  async function fetchWithTimeout(url, timeoutMs = DEFAULT_TIMEOUT) {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeoutMs);
    try {
      const response = await fetch(url, { signal: controller.signal });
      clearTimeout(timeoutId);
      return response;
    } catch (error) {
      clearTimeout(timeoutId);
      if (error.name === "AbortError") {
        throw new Error(`Request timed out after ${timeoutMs}ms`);
      }
      throw error;
    }
  }

  // ===== SHARED: Fire rating normalization =====
  function normalizeFireRating(raw, edgeFallback = 0) {
    const str = (raw ?? "").toString().trim();
    const upper = str.toUpperCase();
    const map = { MAX: 5, ELITE: 5, STRONG: 4, GOOD: 3, STANDARD: 2, LOW: 1 };

    if (upper in map) return map[upper];

    if (str.includes("%")) {
      const pct = parseFloat(str.replace("%", ""));
      if (!Number.isNaN(pct)) {
        if (pct >= 80) return 5;
        if (pct >= 65) return 4;
        if (pct >= 50) return 3;
        if (pct >= 35) return 2;
        return 1;
      }
    }

    const asNum = parseInt(str, 10);
    if (!Number.isNaN(asNum) && str !== "")
      return Math.max(0, Math.min(5, asNum));

    // Fallback: derive from edge value
    if (typeof edgeFallback === "number" && edgeFallback > 0) {
      return Math.max(0, Math.min(5, Math.ceil(edgeFallback / 1.5)));
    }

    return 3; // default
  }

  // ===== SHARED: Endpoint resolution =====
  function getBaseApiUrl() {
    return (
      window.APP_CONFIG?.API_BASE_URL ||
      window.APP_CONFIG?.API_BASE_FALLBACK ||
      `${window.location.origin}/api`
    );
  }

  function getFunctionsBase() {
    const configured =
      window.APP_CONFIG?.FUNCTIONS_BASE_URL || window.location.origin;
    const normalized = String(configured || "").replace(/\/+$/, "");

    // Guard against local/dev configs that accidentally include `/api`
    // because sport fetchers append `/api/...` routes themselves.
    return normalized.replace(/\/api$/i, "");
  }

  function getContainerEndpoint(sport) {
    const resolved = window.ModelEndpointResolver?.getApiEndpoint(sport);
    if (resolved) return resolved;
    const configKey = `${sport.toUpperCase()}_API_URL`;
    const fromConfig = window.APP_CONFIG?.[configKey];
    if (fromConfig) return fromConfig;
    const fallback = window.APP_CONFIG?.API_BASE_FALLBACK;
    return fallback ? `${fallback}/${sport.toLowerCase()}` : "";
  }

  // ===== BaseSportFetcher class =====

  /**
   * @param {Object} config
   * @param {string} config.sport - e.g. 'NBA', 'NCAAM', 'NFL'
   * @param {string} config.tag - Log prefix, e.g. '[NBA-FETCHER]'
   * @param {Function} config.buildPrimaryUrl - (date) => url string
   * @param {Function} config.buildFallbackUrl - (date) => url string
   * @param {Function} config.formatPickForTable - (rawPick) => formatted pick
   * @param {number} [config.timeoutMs] - Request timeout
   * @param {number} [config.cacheDurationMs] - Cache TTL
   * @param {Function} [config.onFetchFail] - Optional hook for sport-specific retry logic
   */
  function BaseSportFetcher(config) {
    this.sport = config.sport;
    this.tag = config.tag || `[${config.sport}-FETCHER]`;
    this.buildPrimaryUrl = config.buildPrimaryUrl;
    this.buildFallbackUrl = config.buildFallbackUrl;
    this.formatPickForTable = config.formatPickForTable;
    this.timeoutMs = config.timeoutMs || DEFAULT_TIMEOUT;
    this.cacheDurationMs = config.cacheDurationMs || DEFAULT_CACHE_DURATION;
    this.onFetchFail = config.onFetchFail || null;

    // Per-date cache
    this._cache = {};
    this._lastSource = null;
  }

  BaseSportFetcher.prototype.fetchPicks = async function (date, options) {
    date = date || "today";
    const skipCache = options?.skipCache || false;

    if (window.ModelEndpointResolver?.ensureRegistryHydrated) {
      window.ModelEndpointResolver.ensureRegistryHydrated();
    }

    // Cache check (skip when forced refresh)
    if (!skipCache) {
      const cached = this._cache[date];
      if (cached && Date.now() - cached.timestamp < this.cacheDurationMs) {
        return cached.data;
      }
    }

    let primaryUrl = this.buildPrimaryUrl(date);

    // Append cache-bust param to bypass backend in-memory cache
    if (skipCache) {
      const separator = primaryUrl.includes("?") ? "&" : "?";
      primaryUrl += `${separator}_nocache=${Date.now()}`;
    }

    // [CORS-HOTFIX] Force same-origin proxy for production to avoid CORS blocks from ACA
    if (!window.APP_CONFIG.IS_LOCAL_DEV && !primaryUrl.startsWith(window.location.origin) && !primaryUrl.startsWith('/')) {
        const urlObj = new URL(primaryUrl);
        // Rewrite https://some-aca.io/path -> /api/model/sport/path
        // This relies on the convention that buildPrimaryUrl already tried to use getFunctionsBase()
        // but if it failed or returned a direct URL, we force it back to the proxy.
        // Actually, let's just ensure it uses getFunctionsBase() correcty.
    }

    try {
      let response = await fetchWithTimeout(primaryUrl, this.timeoutMs);

      if (!response.ok) {
        const fallbackUrl = this.buildFallbackUrl(date);
        // ONLY use fallback (direct ACA) if we are in local dev or if explicitly allowed.
        // In production, direct ACA calls will usually fail due to CORS.
        if (fallbackUrl && (window.APP_CONFIG.IS_LOCAL_DEV || window.APP_CONFIG.ALLOW_DIRECT_FALLBACK)) {
          response = await fetchWithTimeout(fallbackUrl, this.timeoutMs);
        }

        // Sport-specific retry hook (e.g. NCAAM trigger-picks)
        if (!response.ok && this.onFetchFail) {
          const retryResponse = await this.onFetchFail(date, response);
          if (retryResponse) response = retryResponse;
        }

        if (!response.ok) {
          throw new Error(`${this.tag} All routes failed (${response.status})`);
        }
        this._lastSource = "fallback";
      } else {
        this._lastSource = "primary";
      }

      const data = await response.json();

      // Cache with date key
      this._cache[date] = { data, timestamp: Date.now() };

      return data;
    } catch (error) {
      throw error;
    }
  };

  BaseSportFetcher.prototype.checkHealth = async function () {
    const endpoint = getContainerEndpoint(this.sport.toLowerCase());
    try {
      const response = await fetchWithTimeout(`${endpoint}/health`, 5000);
      if (response.ok) {
        const data = await response.json();
        return { status: "healthy", ...data, containerApp: endpoint };
      }
      return { status: "error", code: response.status, containerApp: endpoint };
    } catch (error) {
      return {
        status: "error",
        message: error.message,
        containerApp: endpoint,
      };
    }
  };

  BaseSportFetcher.prototype.clearCache = function (date) {
    if (date) {
      delete this._cache[date];
    } else {
      this._cache = {};
    }
  };

  BaseSportFetcher.prototype.getCache = function (date) {
    return this._cache[date || "today"]?.data || null;
  };

  BaseSportFetcher.prototype.getLastSource = function () {
    return this._lastSource;
  };

  // ===== SHARED: Team name & record resolution via TeamData =====
  function resolveTeam(rawName, sport) {
    if (!rawName) return { fullName: "", abbr: "" };
    const info = window.TeamData?.getTeamInfo?.(rawName, sport?.toLowerCase());
    return {
      fullName: (info && info.fullName) || rawName,
      abbr: (info && info.abbr) || "",
    };
  }

  // Export shared utilities and base class
  window.BaseSportFetcher = BaseSportFetcher;
  window.BaseSportFetcher.utils = {
    fetchWithTimeout,
    normalizeFireRating,
    getBaseApiUrl,
    getFunctionsBase,
    getContainerEndpoint,
    resolveTeam,
  };
})();


